import{_ as a,c as e,o as l,ae as s}from"./chunks/framework.Dh1jimFm.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"client-doc/core/updatePwd.md","filePath":"client-doc/core/updatePwd.md","lastUpdated":1770358354000}'),n={name:"client-doc/core/updatePwd.md"};function i(o,t,r,d,p,c){return l(),e("div",null,t[0]||(t[0]=[s(`<h3 id="定期修改密码" tabindex="-1">定期修改密码 <a class="header-anchor" href="#定期修改密码" aria-label="Permalink to &quot;定期修改密码&quot;">​</a></h3><h4 id="接口概述" tabindex="-1">接口概述 <a class="header-anchor" href="#接口概述" aria-label="Permalink to &quot;接口概述&quot;">​</a></h4><p>提供用户修改个人密码的安全接口，包含多重验证和强度检测机制。</p><h4 id="接口定义" tabindex="-1">接口定义 <a class="header-anchor" href="#接口定义" aria-label="Permalink to &quot;接口定义&quot;">​</a></h4><p>java</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@Log(title = &quot;个人信息&quot;, businessType = BusinessType.UPDATE)</span></span>
<span class="line"><span>@PutMapping(&quot;/updatePwd&quot;)</span></span>
<span class="line"><span>@Operation(summary = &quot;修改密码&quot;)</span></span>
<span class="line"><span>public AjaxResult updatePwd(@RequestBody Map&lt;String, String&gt; params)</span></span></code></pre></div><h3 id="参数说明" tabindex="-1">参数说明 <a class="header-anchor" href="#参数说明" aria-label="Permalink to &quot;参数说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">参数名</th><th style="text-align:left;">类型</th><th style="text-align:left;">必填</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">oldPassword</td><td style="text-align:left;">String</td><td style="text-align:left;">是</td><td style="text-align:left;">当前使用的旧密码</td></tr><tr><td style="text-align:left;">newPassword</td><td style="text-align:left;">String</td><td style="text-align:left;">是</td><td style="text-align:left;">要设置的新密码</td></tr></tbody></table><h3 id="业务逻辑流程" tabindex="-1">业务逻辑流程 <a class="header-anchor" href="#业务逻辑流程" aria-label="Permalink to &quot;业务逻辑流程&quot;">​</a></h3><ol><li><strong>参数验证</strong>：提取并验证新旧密码参数</li><li><strong>用户身份验证</strong>：获取当前登录用户信息</li><li><strong>旧密码验证</strong>：检查旧密码是否正确</li><li><strong>重复性检查</strong>：确保新密码不与旧密码相同</li><li><strong>密码强度检测</strong>：调用<code>PasswordStrengthChecker</code>进行强度验证</li><li><strong>密码加密</strong>：对新密码进行安全加密</li><li><strong>数据更新</strong>：更新数据库中的用户密码</li><li><strong>缓存同步</strong>：更新登录用户的缓存信息</li></ol><hr><h4 id="密码强度检测器" tabindex="-1">密码强度检测器 <a class="header-anchor" href="#密码强度检测器" aria-label="Permalink to &quot;密码强度检测器&quot;">​</a></h4><h4 id="类定义" tabindex="-1">类定义 <a class="header-anchor" href="#类定义" aria-label="Permalink to &quot;类定义&quot;">​</a></h4><p><code>PasswordStrengthChecker</code> - 密码强度检测工具类</p><h4 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h4><p>基础检测规则</p><ul><li><strong>长度要求</strong>：8-20个字符</li><li><strong>字符类型要求</strong>： <ul><li>必须包含大写字母（A-Z）</li><li>必须包含小写字母（a-z）</li><li>必须包含数字（0-9）</li><li>必须包含特殊字符（!@#$%^&amp;*等）</li></ul></li></ul><p>安全限制规则</p><ul><li><strong>禁止连续数字</strong>：防止&quot;123&quot;、&quot;456&quot;等连续数字序列</li><li><strong>禁止重复字符</strong>：防止&quot;aaa&quot;、&quot;111&quot;等连续相同字符</li><li><strong>禁止非法字符</strong>：只允许字母、数字和特定特殊字符</li></ul><h4 id="正则表达式模式" tabindex="-1">正则表达式模式 <a class="header-anchor" href="#正则表达式模式" aria-label="Permalink to &quot;正则表达式模式&quot;">​</a></h4><p>java</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 检测连续数字的模式（3位及以上连续数字）</span></span>
<span class="line"><span>private static final Pattern SEQUENTIAL_DIGIT_PATTERN =</span></span>
<span class="line"><span>        Pattern.compile(&quot;(012|123|234|345|456|567|678|789|890|987|876|765|654|543|432|321|210)&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 检测连续相同字符的模式</span></span>
<span class="line"><span>private static final Pattern REPEAT_CHAR_PATTERN =</span></span>
<span class="line"><span>        Pattern.compile(&quot;(.)\\\\1\\\\1&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 特殊字符模式（常见的特殊字符）</span></span>
<span class="line"><span>private static final Pattern SPECIAL_CHAR_PATTERN =</span></span>
<span class="line"><span>        Pattern.compile(&quot;[!@#$%^&amp;*()_+\\\\-=\\\\[\\\\]{};&#39;:\\&quot;\\\\\\\\|,.&lt;&gt;\\\\/?]&quot;);</span></span></code></pre></div><h4 id="主要方法" tabindex="-1">主要方法 <a class="header-anchor" href="#主要方法" aria-label="Permalink to &quot;主要方法&quot;">​</a></h4><h4 id="_1-checkpasswordstrength-string-password" tabindex="-1">1. <code>checkPasswordStrength(String password)</code> <a class="header-anchor" href="#_1-checkpasswordstrength-string-password" aria-label="Permalink to &quot;1. \`checkPasswordStrength(String password)\`&quot;">​</a></h4><p><strong>功能</strong>：检测密码强度并返回结果</p><p><strong>返回类型</strong>：<code>PasswordCheckResult</code></p><ul><li><code>isStrong</code>：是否通过强度检测</li><li><code>message</code>：检测结果信息</li><li><code>score</code>：密码强度分数（0-10分）</li></ul><h4 id="_2-验证方法" tabindex="-1">2. 验证方法 <a class="header-anchor" href="#_2-验证方法" aria-label="Permalink to &quot;2. 验证方法&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">方法名</th><th style="text-align:left;">功能说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>containsUpperCase()</code></td><td style="text-align:left;">检查是否包含大写字母</td></tr><tr><td style="text-align:left;"><code>containsLowerCase()</code></td><td style="text-align:left;">检查是否包含小写字母</td></tr><tr><td style="text-align:left;"><code>containsDigit()</code></td><td style="text-align:left;">检查是否包含数字</td></tr><tr><td style="text-align:left;"><code>containsSpecialChar()</code></td><td style="text-align:left;">检查是否包含特殊字符</td></tr><tr><td style="text-align:left;"><code>containsIllegalChars()</code></td><td style="text-align:left;">检查是否包含非法字符</td></tr><tr><td style="text-align:left;"><code>containsThreeSequentialDigits()</code></td><td style="text-align:left;">检查是否包含连续数字</td></tr></tbody></table><h4 id="_3-calculatepasswordscore-string-password" tabindex="-1">3. <code>calculatePasswordScore(String password)</code> <a class="header-anchor" href="#_3-calculatepasswordscore-string-password" aria-label="Permalink to &quot;3. \`calculatePasswordScore(String password)\`&quot;">​</a></h4><p><strong>功能</strong>：计算密码强度分数</p><p><strong>评分维度</strong>：</p><ul><li><strong>长度得分</strong>：8-11字符(1分)、12-15字符(2分)、16+字符(3分)</li><li><strong>字符类型得分</strong>：包含每种字符类型各得1分（共4分）</li><li><strong>复杂度加分</strong>： <ul><li>特殊字符≥3个：2分</li><li>特殊字符=2个：1分</li><li>大小写字母比例均衡：1分</li><li>数字字母交叉模式：1分</li></ul></li></ul><h4 id="结果类定义" tabindex="-1">结果类定义 <a class="header-anchor" href="#结果类定义" aria-label="Permalink to &quot;结果类定义&quot;">​</a></h4><p>java</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>public static class PasswordCheckResult {</span></span>
<span class="line"><span>    private final boolean isStrong;    // 是否通过强度检测</span></span>
<span class="line"><span>    private final String message;      // 检测结果信息</span></span>
<span class="line"><span>    private final int score;           // 密码强度分数</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // 构造方法和getter方法</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h4 id="测试用例" tabindex="-1">测试用例 <a class="header-anchor" href="#测试用例" aria-label="Permalink to &quot;测试用例&quot;">​</a></h4><p>测试密码示例</p><table tabindex="0"><thead><tr><th style="text-align:left;">测试密码</th><th style="text-align:left;">预期结果</th><th style="text-align:left;">原因说明</th></tr></thead><tbody><tr><td style="text-align:left;">&quot;123456aB&quot;</td><td style="text-align:left;">不通过</td><td style="text-align:left;">无特殊字符</td></tr><tr><td style="text-align:left;">&quot;Abcdefg1&quot;</td><td style="text-align:left;">不通过</td><td style="text-align:left;">无特殊字符</td></tr><tr><td style="text-align:left;">&quot;Abc123!@&quot;</td><td style="text-align:left;">通过</td><td style="text-align:left;">符合所有要求</td></tr><tr><td style="text-align:left;">&quot;ABcdefg1!&quot;</td><td style="text-align:left;">通过</td><td style="text-align:left;">符合所有要求</td></tr><tr><td style="text-align:left;">&quot;aB1!aaaa&quot;</td><td style="text-align:left;">不通过</td><td style="text-align:left;">连续相同字符</td></tr><tr><td style="text-align:left;">&quot;aB1!123456&quot;</td><td style="text-align:left;">不通过</td><td style="text-align:left;">连续数字</td></tr><tr><td style="text-align:left;">&quot;A1!aaaa&quot;</td><td style="text-align:left;">不通过</td><td style="text-align:left;">长度不足</td></tr><tr><td style="text-align:left;">&quot;Password123!&quot;</td><td style="text-align:left;">通过</td><td style="text-align:left;">符合所有要求</td></tr><tr><td style="text-align:left;">&quot;Test@2023&quot;</td><td style="text-align:left;">通过</td><td style="text-align:left;">符合所有要求</td></tr></tbody></table><hr><h2 id="安全特性" tabindex="-1">安全特性 <a class="header-anchor" href="#安全特性" aria-label="Permalink to &quot;安全特性&quot;">​</a></h2><h4 id="多重验证" tabindex="-1">多重验证 <a class="header-anchor" href="#多重验证" aria-label="Permalink to &quot;多重验证&quot;">​</a></h4><ul><li><strong>旧密码验证</strong>：确保只有合法用户才能修改密码</li><li><strong>密码强度验证</strong>：防止设置弱密码</li><li><strong>重复性检查</strong>：防止新旧密码相同</li></ul><h4 id="加密保护" tabindex="-1">加密保护 <a class="header-anchor" href="#加密保护" aria-label="Permalink to &quot;加密保护&quot;">​</a></h4><ul><li><strong>密码加密</strong>：使用<code>SecurityUtils.encryptPassword()</code>进行安全加密</li><li><strong>对比验证</strong>：使用<code>SecurityUtils.matchesPassword()</code>进行安全对比</li></ul><h4 id="缓存同步" tabindex="-1">缓存同步 <a class="header-anchor" href="#缓存同步" aria-label="Permalink to &quot;缓存同步&quot;">​</a></h4><ul><li><strong>用户信息更新</strong>：更新缓存中的用户密码信息</li><li><strong>时间戳更新</strong>：记录密码最后修改时间</li></ul><h4 id="日志记录" tabindex="-1">日志记录 <a class="header-anchor" href="#日志记录" aria-label="Permalink to &quot;日志记录&quot;">​</a></h4><ul><li><strong>操作日志</strong>：记录密码修改操作</li><li><strong>业务日志</strong>：区分不同业务类型的操作</li></ul><hr><h4 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to &quot;使用场景&quot;">​</a></h4><p>定期密码修改</p><p>用户按照安全策略定期修改密码。</p><p>安全事件响应</p><p>检测到异常登录行为后强制修改密码。</p><p>首次登录</p><p>新用户首次登录时强制修改初始密码。</p>`,58)]))}const u=a(n,[["render",i]]);export{g as __pageData,u as default};
